module portfolio_optimizer(
    input [4:0] obf_assets,
    output [4:0] optimal_selection
);
    assign optimal_selection[0] = obf_assets[0];
    assign optimal_selection[1] = obf_assets[1];
    assign optimal_selection[2] = obf_assets[2];
    assign optimal_selection[3] = obf_assets[3];
    assign optimal_selection[4] = (obf_assets[3]) ? 1'b0 : obf_assets[4];
endmodule
